import { ChangeDetectionStrategy, Component, ElementRef, afterNextRender, computed, inject, signal, viewChild } from '@angular/core';
import { interval } from 'rxjs';
import { AXColorUtil, AXHtmlUtil, AXUnsubscriber, delay, retryUntil } from '@acorex/core/utils';

@Component({
  selector: 'app-utils-basic-usage',
  providers: [AXUnsubscriber],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <section #panel>
      <button type="button" (click)="load()">Load</button>
      <p>Status: {{ status() }}</p>
      <p>Accent: {{ accentHex() }}</p>
    </section>
  `,
})
export class UtilsBasicUsageComponent {
  private readonly unsubscriber = inject(AXUnsubscriber);
  private readonly panel = viewChild<ElementRef<HTMLElement>>('panel');

  protected readonly status = signal('Idle');
  protected readonly accent = signal('rgba(51, 102, 153, 0.8)');
  protected readonly accentHex = computed(() => AXColorUtil.colorStringToHex(this.accent()));

  constructor() {
    afterNextRender(() => {
      const panel = this.panel()?.nativeElement;
      if (panel) {
        AXHtmlUtil.focusElement(panel);
      }
    });

    interval(1000)
      .pipe(this.unsubscriber.takeUntilDestroy)
      .subscribe(() => this.status.set('Watching...'));
  }

  protected async load() {
    this.status.set('Loading...');
    await delay(300);

    const result = await retryUntil(() => this.fetchData(), 3, 250);
    this.status.set(result.message);
  }

  private async fetchData(): Promise<{ message: string }> {
    const response = await fetch('/api/data');
    if (!response.ok) {
      throw new Error('Request failed');
    }
    return response.json();
  }
}

import { delay, retryUntil, pollUntil, pollUntilAbortable, fallbackChain } from '@acorex/core/utils';

// Simple sleep
await delay(500);

// Retry API call up to 5 times with 300ms between attempts
const data = await retryUntil(() => fetch('/api/data').then(r => r.json()), 5, 300);

// Wait until a condition becomes true
await pollUntil(() => document.querySelector('.ready') !== null, 100, 5000);

// Cancellable poll
const controller = new AbortController();
try {
  await pollUntilAbortable(() => isLoaded(), 50, 3000, controller.signal);
} catch {
  console.log('Polling cancelled or timed out');
}

// Try primary source, fall back to secondary
const config = await fallbackChain([
  () => fetch('/config.json').then(r => r.json()),
  () => fetch('/config.fallback.json').then(r => r.json()),
]);

import { waitFor } from '@acorex/core/utils';

const cache = new Map<string, string>();

function loadIntoCache(key: string) {
  setTimeout(() => cache.set(key, 'loaded-value'), 50);
}

function getSync(key: string): string | null {
  return waitFor(
    () => cache.get(key) ?? null,   // peek
    () => loadIntoCache(key),        // trigger load once
    200,                             // timeout ms
  );
}

