import { throttleAsync, debounceAsync } from '@acorex/core/utils';

// Only one save operation at a time
const save = throttleAsync(async (payload: unknown) => {
  await fetch('/api/save', { method: 'POST', body: JSON.stringify(payload) });
});

// Search after user stops typing for 300ms
const search = debounceAsync(async (query: string) => {
  return fetch(`/api/search?q=${query}`).then(r => r.json());
}, 300);

await search('angular');
await search('angular material'); // only last call runs after 300ms

import { AXHtmlUtil } from '@acorex/core/utils';
import { ElementRef, inject } from '@angular/core';

function setupDialog(container: HTMLElement) {
  // Focus first focusable child (used by MXInteractiveComponent.focus)
  AXHtmlUtil.focusElement(container);

  // Check RTL for layout (menu, data-pager, editor)
  const rtl = AXHtmlUtil.isRtl(container);
  if (rtl) container.classList.add('ax-rtl');

  // Find scroll containers for overlay positioning (menu)
  const scrollParents = AXHtmlUtil.getScrollableParents(container);

  // Check focus state
  if (AXHtmlUtil.hasFocus(container)) {
    console.log('Container is focused');
  }
}

import { AXDrawingUtil, AXPoint } from '@acorex/core/utils';

function handleClick(event: MouseEvent, target: HTMLElement) {
  const point: AXPoint = { x: event.clientX, y: event.clientY };

  if (AXDrawingUtil.isInElementBound(point, target)) {
    console.log('Click inside element');
  }

  // Check overlap between two elements
  const other = document.querySelector('.overlay') as HTMLElement;
  if (other && AXDrawingUtil.collision(target, other)) {
    console.log('Elements overlap');
  }

  // Convert rem to px for canvas/layout math
  const px = AXDrawingUtil.convertRemToPixels(1.5);
}

