import { Component, inject, OnDestroy } from '@angular/core';
import { AXUnsubscriber } from '@acorex/core/utils';
import { DataService } from './data.service';

@Component({
  selector: 'app-select-box',
  providers: [AXUnsubscriber],
  template: `...`,
})
export class SelectBoxComponent implements OnDestroy {
  private unsubscriber = inject(AXUnsubscriber);
  private dataService = inject(DataService);

  ngOnInit() {
    this.dataService.items$
      .pipe(this.unsubscriber.takeUntilDestroy)
      .subscribe(items => this.render(items));

    this.dataService.loading$
      .pipe(this.unsubscriber.takeUntilDestroy)
      .subscribe(loading => this.isLoading = loading);
  }

  ngOnDestroy() {
    this.unsubscriber.unsubscribe();
  }
}

import { Component, OnDestroy } from '@angular/core';
import { AXAutoUnsubscriber } from '@acorex/core/utils';
import { interval } from 'rxjs';

@AXAutoUnsubscriber()
@Component({
  template: `<p>Tick: {{ tick }}</p>`,
})
export class TickComponent implements OnDestroy {
  tick = 0;

  // Any property with .subscribe() is auto-unsubscribed in ngOnDestroy
  private sub = interval(1000).subscribe(n => (this.tick = n));

  ngOnDestroy() {
    // Your own cleanup + decorator runs property unsubscribe
  }
}

import { getWordBoundsAtPosition } from '@acorex/core/utils';

function selectWordAtCursor(input: HTMLInputElement) {
  const text = input.value;
  const pos = input.selectionStart ?? 0;
  const { start, end } = getWordBoundsAtPosition(text, pos);

  input.setSelectionRange(start, end);
  return text.slice(start, end);
}

